import React, { useState, useEffect } from 'react';
import { 
  Users, CreditCard, Settings, Bell, Home, User, Lock, LogOut, 
  Smartphone, Zap, ShieldCheck, CheckCircle2, ArrowLeft, ChevronRight, 
  CreditCard as CardIcon, Eye, Download, X, Save, ShieldAlert, Landmark, Menu, FileText, Calendar, Clock, Check
} from 'lucide-react';

const App = () => {
  const [userRole, setUserRole] = useState(null); 
  const [loginMode, setLoginMode] = useState('tenant'); 
  const [activeTab, setActiveTab] = useState('Dashboard');
  
  // --- SRS Final Updated Settings ---
  const [globalSettings, setGlobalSettings] = useState({
    lateFeePerDay: 50,
    gracePeriod: 5
  });

  const [tenants, setTenants] = useState([
    { 
      id: 1, 
      name: 'Rajesh Kumar', 
      room: 'A-101', 
      status: 'No Request', 
      rentAmount: 12500,
      dueDate: '2026-04-01', // Example date to trigger late fee
      electricity: { old: 1050, current: 1150, pricePerUnit: 8, units: 100, total: 800 },
      lastPayment: null
    }
  ]);

  // 2.1.2: Late Fee Calculation Logic
  const calculateLateFee = (dueDate) => {
    const today = new Date();
    const due = new Date(dueDate);
    const diffTime = today - due;
    const diffDays = Math.floor(diffTime / (1000 * 60 * 60 * 24));
    
    const lateDays = diffDays - globalSettings.gracePeriod;
    if (lateDays > 0) {
      return { days: lateDays, amount: lateDays * globalSettings.lateFeePerDay };
    }
    return { days: 0, amount: 0 };
  };

  const handleRequestApproval = (tenantId) => {
    setTenants(prev => prev.map(t => t.id === tenantId ? { ...t, status: 'Pending Approval' } : t));
  };

  const processDecision = (tenantId, decision) => {
    const status = decision === 'Approve' ? 'Approved' : 'Rejected';
    const feeInfo = calculateLateFee(tenants.find(t => t.id === tenantId).dueDate);
    
    setTenants(prev => prev.map(t => t.id === tenantId ? { 
      ...t, 
      status: status,
      lastPayment: status === 'Approved' ? {
        date: new Date().toLocaleString(),
        total: t.rentAmount + t.electricity.total + feeInfo.amount,
        lateFee: feeInfo.amount,
        lateDays: feeInfo.days
      } : null
    } : t));
  };

  if (!userRole) {
    return (
      <div className="min-h-screen bg-[#0F172A] flex items-center justify-center p-6">
        <div className="w-full max-w-md bg-white rounded-[2.5rem] p-10 shadow-2xl">
          <div className="flex justify-center mb-8">
             <div className="w-16 h-16 bg-indigo-600 rounded-3xl flex items-center justify-center text-white text-2xl font-black italic">H</div>
          </div>
          <div className="flex gap-2 p-1 bg-slate-100 rounded-2xl mb-8">
            <button onClick={() => setLoginMode('tenant')} className={`flex-1 py-4 rounded-xl text-[10px] font-black uppercase transition-all ${loginMode === 'tenant' ? 'bg-white text-indigo-600 shadow-lg' : 'text-slate-400'}`}>Resident</button>
            <button onClick={() => setLoginMode('admin')} className={`flex-1 py-4 rounded-xl text-[10px] font-black uppercase transition-all ${loginMode === 'admin' ? 'bg-white text-indigo-600 shadow-lg' : 'text-slate-400'}`}>Landlord</button>
          </div>
          <button onClick={() => setUserRole(loginMode)} className="w-full bg-slate-900 text-white font-black py-5 rounded-2xl uppercase tracking-widest text-xs hover:bg-indigo-600 transition-all">Enter Portal</button>
        </div>
      </div>
    );
  }

  return userRole === 'admin' ? (
    <AdminPortal tenants={tenants} onDecision={processDecision} logout={() => setUserRole(null)} />
  ) : (
    <TenantPortal tenant={tenants[0]} lateFeeCalc={calculateLateFee} onRequest={handleRequestApproval} logout={() => setUserRole(null)} />
  );
};

// --- LANDLORD PORTAL ---
const AdminPortal = ({ tenants, onDecision, logout }) => {
  const [activeTab, setActiveTab] = useState('Approvals');

  return (
    <div className="flex h-screen bg-[#F8FAFC]">
      <aside className="w-72 bg-slate-900 text-white p-8 hidden md:flex flex-col">
        <div className="font-black italic text-xl mb-12 uppercase tracking-tighter">Homely Admin</div>
        <nav className="space-y-2">
          {['Approvals', 'Settings'].map(t => (
            <button key={t} onClick={() => setActiveTab(t)} className={`w-full text-left px-6 py-4 rounded-xl text-[10px] font-black uppercase tracking-widest ${activeTab === t ? 'bg-indigo-600' : 'text-slate-500'}`}>{t}</button>
          ))}
          <button onClick={logout} className="w-full text-left px-6 py-4 text-red-400 text-[10px] font-black uppercase mt-auto">Logout</button>
        </nav>
      </aside>

      <main className="flex-1 p-12 overflow-y-auto">
        <h3 className="text-2xl font-black italic uppercase mb-8">Pending Approvals</h3>
        <div className="space-y-6">
          {tenants.filter(t => t.status === 'Pending Approval').map(t => (
            <div key={t.id} className="bg-white p-8 rounded-[2.5rem] border flex items-center justify-between shadow-sm">
              <div>
                <p className="font-black text-lg italic">{t.name} ({t.room})</p>
                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Awaiting Confirmation</p>
              </div>
              <div className="flex gap-4">
                <button onClick={() => onDecision(t.id, 'Approve')} className="p-4 bg-emerald-500 text-white rounded-2xl hover:scale-110 transition-transform"><Check/></button>
                <button onClick={() => onDecision(t.id, 'Reject')} className="p-4 bg-red-500 text-white rounded-2xl hover:scale-110 transition-transform"><X/></button>
              </div>
            </div>
          ))}
        </div>
      </main>
    </div>
  );
};

// --- TENANT PORTAL ---
const TenantPortal = ({ tenant, lateFeeCalc, onRequest, logout }) => {
  const feeInfo = lateFeeCalc(tenant.dueDate);
  const totalPayable = tenant.rentAmount + tenant.electricity.total + feeInfo.amount;

  return (
    <div className="min-h-screen bg-slate-50 p-6 md:p-12">
      <div className="max-w-4xl mx-auto space-y-8">
        <header className="flex justify-between items-center mb-8">
          <div className="text-2xl font-black italic text-indigo-600">MY RESIDENCE</div>
          <button onClick={logout} className="p-4 bg-white rounded-2xl border text-red-500 shadow-sm"><LogOut size={20}/></button>
        </header>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
          <div className="bg-slate-900 p-12 rounded-[3.5rem] text-white shadow-2xl relative">
             <div className="absolute top-0 right-0 p-8">
               <span className={`text-[8px] font-black uppercase px-3 py-1 rounded-full ${feeInfo.amount > 0 ? 'bg-red-500' : 'bg-emerald-500'}`}>
                 {feeInfo.amount > 0 ? 'Late Fee Applied' : 'Grace Period'}
               </span>
             </div>
             <p className="text-[10px] font-black text-indigo-300 uppercase mb-4 italic">Payable Amount</p>
             <h2 className="text-6xl font-black italic mb-8">₹{totalPayable.toLocaleString()}</h2>
             
             {tenant.status === 'No Request' || tenant.status === 'Rejected' ? (
               <button onClick={onRequest} className="w-full py-5 bg-indigo-600 rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl hover:bg-indigo-500 transition-all">Request Approval</button>
             ) : (
               <div className={`w-full py-5 rounded-2xl font-black uppercase text-xs text-center flex items-center justify-center gap-2 ${tenant.status === 'Approved' ? 'bg-emerald-500' : 'bg-orange-500/20 text-orange-400'}`}>
                 {tenant.status === 'Approved' ? <CheckCircle2 size={16}/> : <Clock size={16}/>} {tenant.status}
               </div>
             )}
          </div>

          <div className="bg-white p-12 rounded-[3.5rem] border shadow-sm space-y-6">
            <h4 className="text-[10px] font-black text-slate-400 uppercase italic">Breakdown</h4>
            <div className="space-y-4 text-xs font-bold">
              <div className="flex justify-between"><span>Base Rent</span> <span>₹{tenant.rentAmount}</span></div>
              <div className="flex justify-between"><span>Electricity Bill</span> <span>₹{tenant.electricity.total}</span></div>
              <div className="flex justify-between text-red-500"><span>Late Fee ({feeInfo.days} Days)</span> <span>+ ₹{feeInfo.amount}</span></div>
            </div>
          </div>
        </div>

        {/* 2.4: Final Receipt System */}
        {tenant.status === 'Approved' && (
          <div className="bg-white p-12 rounded-[4rem] border-4 border-dashed border-slate-100 animate-in fade-in">
             <h3 className="text-2xl font-black italic uppercase mb-8">Payment Receipt</h3>
             <div className="space-y-4 border-t pt-8">
                <div className="flex justify-between text-sm font-bold"><span>Total Settled</span> <span>₹{tenant.lastPayment.total}</span></div>
                <div className="flex justify-between text-[10px] text-slate-400 uppercase font-black"><span>Date</span> <span>{tenant.lastPayment.date}</span></div>
             </div>
             <button className="w-full mt-8 py-4 bg-slate-900 text-white rounded-2xl font-black uppercase text-[10px] flex items-center justify-center gap-2"><Download size={16}/> Get PDF</button>
          </div>
        )}
      </div>
    </div>
  );
};

export default App;
